import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "GuessTheGame",
  description: "Guess the video game from a few images.",
};

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <body className="min-h-dvh antialiased">
        <div className="mx-auto max-w-3xl px-4 py-6">
          <header className="mb-6 flex items-center justify-between gap-3">
            <div className="text-xs font-semibold uppercase tracking-[0.18em] text-muted">HEADER</div>
            <div className="flex-1 pl-2">
              <div className="text-xl font-semibold tracking-tight">GuessTheGame</div>
              <div className="text-sm text-muted">A daily video game guessing challenge.</div>
            </div>
            <nav className="flex items-center gap-2">
              <a
                className="rounded-lg border border-line bg-card px-3 py-2 text-sm text-ink shadow-sm hover:bg-slate-50"
                href="/game">
                Play today&apos;s game
              </a>
            </nav>
          </header>
          {children}
          <footer className="mt-12 border-t border-line pt-8 text-xs text-muted">
            <div className="mb-4 font-semibold uppercase tracking-[0.18em] text-ink">FOOTER</div>
            <div className="grid gap-6 sm:grid-cols-2">
              <div>
                <div className="mb-2 font-semibold uppercase tracking-wider text-ink">Play</div>
                <nav className="flex flex-wrap gap-x-4 gap-y-1">
                  <a href="/" className="hover:text-ink">Home</a>
                  <a href="/game" className="hover:text-ink">Guess The Game</a>
                  <a href="/book" className="hover:text-ink">Guess The Book</a>
                  <a href="/movie" className="hover:text-ink">Guess The Movie</a>
                  <a href="/logo" className="hover:text-ink">Guess The Logo</a>
                  <a href="/house" className="hover:text-ink">Guess The House</a>
                  <a href="/angle" className="hover:text-ink">Guess The Angle</a>
                  <a href="/phrase" className="hover:text-ink">Guess The Phrase</a>
                  <a href="/song" className="hover:text-ink">Guess The Song</a>
                  <a href="/animal" className="hover:text-ink">Guess The Animal</a>
                  <a href="/plant" className="hover:text-ink">Guess The Plant</a>
                  <a href="/number" className="hover:text-ink">Guess The Number</a>
                  <a href="/price" className="hover:text-ink">Guess The Price</a>
                </nav>
              </div>
              <div>
                <div className="mb-2 font-semibold uppercase tracking-wider text-ink">About</div>
                <p>
                  Daily guessing puzzles. Layout inspired by{" "}
                  <code className="rounded bg-slate-100 px-1">spellsbee.com</code>, gameplay by{" "}
                  <code className="rounded bg-slate-100 px-1">guessthe.game</code>.
                </p>
              </div>
            </div>
            <div className="mt-6 flex flex-wrap items-center justify-between gap-3 border-t border-line pt-6">
              <span>© {new Date().getFullYear()} GuessTheGame. All rights reserved.</span>
            </div>
          </footer>
        </div>
      </body>
    </html>
  );
}

